#include <iostream> 
#include <algorithm> 
using namespace std;
int main()
{
    int a[1005];
    int ans[1005];
    int n,q;
    cin>>n>>q;
    for(int i=0;i<=n-1;i++)
    {
        cin>>a[i];
    }
    sort(a,a+n);

    for(int i=0;i<=q-1;i++)
    {
        int c,x,cs=1;
        cin>>c>>x;
        for(int j=0;j<=c-1;j++)
        {
            cs*=10;
        }
        for(int j=0;j<=n-1;j++)
        {
            if(a[j]%cs==x)
            {
                ans[i]=a[j];
                break;
            }
            else if(j==n-1)
            {
                ans[i]=-1;
                break;
            }
        }       
    }

    for(int i=0;i<=q-1;i++)
    {
        cout<<ans[i]<<endl;
    }
    return 0;
}
